mapper.select:
SELECT 
FROM ENTITIES ENT
WHERE UPDATED_AT >= #{searchSet.startSearchTime, jdbcType=TIMESTAMP}
    AND ENT.CREATED_AT >= date '${searchSet.partitionLowerBoundaryDate}'
    AND ENT.CREATED_AT < date '${searchSet.partitionUpperBoundaryDate}'
ORDER BY UPDATED_AT DESC
LIMIT #{bounds.limit, jdbcType=INTEGER}
OFFSET #{bounds.offset, jdbcType=INTEGER}
